pub async fn deactivate_users(pool: &sqlx::PgPool) -> Result<u64, sqlx::Error> {
    let result = sqlx::query!("UPDATE users SET active = false WHERE active = true")
        .execute(pool)
        .await?;
    Ok(result.rows_affected())
}

